const t=`{% block sw_settings_user_detail_content_confirm_password_modal %} <sw-modal :title="$t('sw-users-permissions.users.user-detail.passwordConfirmation.titleConfirmPasswordModal')" variant="small" @modal-close="onCloseConfirmPasswordModal" > {% block sw_settings_user_detail_content_confirm_password_modal_input__confirm_password %} <mt-password-field v-model="confirmPassword" class="sw-settings-user-detail__confirm-password" name="sw-field--confirm-password" :password-toggle-able="true" autocomplete="current-password" :label="$t('sw-users-permissions.users.user-detail.passwordConfirmation.labelConfirmPassword')" :placeholder="$t('sw-users-permissions.users.user-detail.passwordConfirmation.placeholderConfirmPassword')" @keypress.enter="onSubmitConfirmPassword" /> {% endblock %} {% block sw_settings_user_detail_content_confirm_password_modal_footer %} <template #modal-footer> {% block sw_settings_user_detail_content_confirm_password_modal_actions_cancel %} <mt-button size="small" variant="secondary" @click="onCloseConfirmPasswordModal" > {{ $t('global.default.cancel') }} </mt-button> {% endblock %} {% block sw_settings_user_detail_content_confirm_password_modal_actions_change %} <mt-button variant="primary" :disabled="!confirmPassword" size="small" @click="onSubmitConfirmPassword" > {{ $t('sw-users-permissions.users.user-detail.passwordConfirmation.labelButtonConfirm') }} </mt-button> {% endblock %} </template> {% endblock %} </sw-modal> {% endblock %}`,{Mixin:r}=Shopware,i={template:t,inject:["loginService"],emits:["verified","close"],mixins:[r.getByName("notification")],data(){return{confirmPassword:""}},created(){this.createdComponent()},methods:{createdComponent(){},onSubmitConfirmPassword(){return this.loginService.verifyUserToken(this.confirmPassword).then(s=>{const o={...Shopware.Context.api};o.authToken.access=s;const e={...this.loginService.getBearerAuthentication(),access:s};this.loginService.setBearerAuthentication(e),this.$emit("verified",o)}).catch(()=>{this.createNotificationError({title:this.$t("sw-users-permissions.users.user-detail.passwordConfirmation.notificationPasswordErrorTitle"),message:this.$t("sw-users-permissions.users.user-detail.passwordConfirmation.notificationPasswordErrorMessage")})}).finally(()=>{this.confirmPassword="",this.$emit("close")})},onCloseConfirmPasswordModal(){this.confirmPassword="",this.$emit("close")}}};export{i as default};
